// Validate incoming webhook payload from Apps Script
const body = $input.first().json.body || $input.first().json;

const required = ['spreadsheetId', 'sheetName', 'startRow', 'endRow', 'companyName', 'domain'];
const missing = required.filter(f => !body[f] && body[f] !== 0);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

return [{ json: {
  spreadsheet_id: body.spreadsheetId,
  sheet_name: body.sheetName,
  pocs_sheet_name: body.pocsSheetName || '2. POCs',
  start_row: parseInt(body.startRow),
  end_row: parseInt(body.endRow),
  row_count: parseInt(body.rowCount) || (parseInt(body.endRow) - parseInt(body.startRow) + 1),
  trigger_row: parseInt(body.triggerRow),
  company_name: body.companyName,
  bureau_number: body.bureauNumber || '',
  domain: body.domain,
  street_address: body.streetAddress || '',
  city: body.city || '',
  state: body.state || '',
  timestamp: body.timestamp || new Date().toISOString(),
}}];

