// Parse Seamless.AI response and apply seniority sorting
// Produces exactly 5 POC rows: Org Head, Finance, Ops, HR, Extra
const input = $input.first().json;
const data = input.data || input.results || [];
const companyInfo = $('Validate Webhook Payload').first().json;

if (!data || data.length === 0) {
  return [{ json: {
    ...companyInfo,
    seamless_found: false,
    poc_rows: [],
    revenue: '',
    industry: '',
    sic_code: '',
  }}];
}

// Category definitions with title priority (left = most senior)
const categories = {
  'Org Head': ['CEO', 'President', 'Owner'],
  'Finance Head': ['CFO', 'VP Finance', 'Finance Director', 'Head of Finance'],
  'Operations Head': ['COO', 'VP Operations', 'Director Operations'],
  'HR Head': ['Chief People Officer', 'Chief HR Officer', 'VP Human Resources', 'Human Resources Director'],
};

// Sort contacts into category buckets
const buckets = {
  'Org Head': [],
  'Finance Head': [],
  'Operations Head': [],
  'HR Head': [],
  'Unmatched': [],
};

for (const contact of data) {
  const title = (contact.title || '').toLowerCase();
  let matched = false;

  for (const [cat, titles] of Object.entries(categories)) {
    for (let i = 0; i < titles.length; i++) {
      if (title.includes(titles[i].toLowerCase())) {
        buckets[cat].push({
          ...contact,
          _category: cat,
          _priority: i, // lower = more senior
        });
        matched = true;
        break;
      }
    }
    if (matched) break;
  }

  if (!matched) {
    buckets['Unmatched'].push({ ...contact, _category: 'Extra', _priority: 999 });
  }
}

// Sort each bucket by priority (most senior first)
for (const cat of Object.keys(buckets)) {
  buckets[cat].sort((a, b) => a._priority - b._priority);
}

// Select top 1 per category for rows 1-4
const selected = [];
const usedNames = new Set();

for (const cat of ['Org Head', 'Finance Head', 'Operations Head', 'HR Head']) {
  const best = buckets[cat].find(c => !usedNames.has(c.name));
  if (best) {
    usedNames.add(best.name);
    selected.push({ category: cat, contact: best });
  } else {
    selected.push({ category: cat, contact: null });
  }
}

// Row 5: Best remaining (from any bucket)
const allRemaining = [...Object.values(buckets)].flat()
  .filter(c => !usedNames.has(c.name))
  .sort((a, b) => a._priority - b._priority);

if (allRemaining.length > 0) {
  selected.push({ category: 'Extra', contact: allRemaining[0] });
} else {
  selected.push({ category: 'Extra', contact: null });
}

// Build POC rows
const pocRows = selected.map((sel, idx) => ({
  row_num: idx + 1,
  category: sel.category,
  prospect: sel.contact?.name || '',
  title: sel.contact?.title || '',
  email: sel.contact?.email || '',
  phone: sel.contact?.phone || '',
  li_profile: sel.contact?.liUrl || '',
  department: sel.contact?.department || '',
  seniority: sel.contact?.seniority || '',
  reasoning: sel.contact
    ? `${sel.category} — ${sel.contact.title} (priority ${sel.contact._priority + 1})`
    : `${sel.category} — No match found`,
}));

// Extract company enrichment from first result
const first = data[0] || {};

return [{ json: {
  ...companyInfo,
  seamless_found: true,
  poc_rows: pocRows,
  revenue: first.companyRevenue || first.revenue || '',
  industry: (first.industries || []).join(', ') || first.industry || '',
  sic_code: first.sicCode || '',
}}];

// Write 5 POC rows to the Filtered sheet and POCs sheet
const input = $input.first().json;
const pocRows = input.poc_rows;

// Build update items for the Filtered sheet (5-row block)
const filteredUpdates = [];
for (let i = 0; i < pocRows.length; i++) {
  const row = input.start_row + i;
  filteredUpdates.push({
    json: {
      row_number: row,
      Prospect: pocRows[i].prospect,
      Title: pocRows[i].title,
      'Contact Email': pocRows[i].email,
      'Contact Phone Number': pocRows[i].phone,
      'LI Profile': pocRows[i].li_profile,
      'POC Reasoning': pocRows[i].reasoning,
      'POC Done': i === pocRows.length - 1 ? 'Done' : '',
      // Company enrichment on first row only
      ...(i === 0 ? {
        'Revenue ($M)': input.revenue,
        'Industry': input.industry,
        'SIC Code': input.sic_code,
      } : {}),
    }
  });
}

return filteredUpdates;

// Write all POC results to the POCs sheet
const input = $('Seniority Sort + Parse').first().json;
const pocRows = input.poc_rows;

return pocRows.map(poc => ({
  json: {
    'Primary Name': input.company_name.toUpperCase(),
    'Prospect': poc.prospect,
    'Title': poc.title,
    'Contact Email': poc.email,
    'Contact Phone Number': poc.phone,
    'POC Reasoning': poc.reasoning,
    'POC Row #': '',
    'Contact Last Updated': new Date().toISOString().split('T')[0],
    'Done': 'Done',
  }
}));
